mapper.select:
SELECT p.*, e.equipment_name
FROM inspection_plans p
LEFT JOIN equipment e ON p.equipment_code = e.equipment_code


        AND p.fiscal_year = #{fiscalYear}


        AND e.equipment_type = #{equipmentType}


        AND p.team_code = #{teamCode}


        AND p.equipment_code = #{equipmentCode}


ORDER BY p.planned_date ASC

SELECT COUNT(*)
FROM inspection_plans p
LEFT JOIN equipment e ON p.equipment_code = e.equipment_code


        AND p.fiscal_year = #{fiscalYear}


        AND p.equipment_code = #{equipmentCode}


        AND SUBSTR(p.planned_date, 5, 2) = #{month}

mapper.insert:
INSERT INTO inspection_plans (
    fiscal_year, equipment_code, template_id, planned_date,
    team_code, person_code, status, is_locked, note
) VALUES (
    #{fiscalYear}, #{equipmentCode}, #{templateId}, #{plannedDate},
    #{teamCode}, #{personCode}, #{status}, #{isLocked}, #{note}
)

mapper.update:
UPDATE inspection_plans
SET is_locked = TRUE, updated_at = CURRENT_TIMESTAMP
WHERE fiscal_year = #{fiscalYear}

UPDATE inspection_plans
SET is_locked = FALSE, updated_at = CURRENT_TIMESTAMP
WHERE fiscal_year = #{fiscalYear}
